import { lazy, Suspense, useEffect, useMemo, useRef, useState, type ChangeEvent, type ComponentType, type DragEvent, type LazyExoticComponent } from "react";
import type { FileIoAdapter, PlatformOutput, ResolvedInput } from "@suwol/core";
import { categories, defaultOutputTarget, defaultSettings, getToolById, tools, type AppSettings, type InputItem, type InputSource, type Job, type OutputTarget, type UpdateState } from "@suwol/shared";
import type { FeatureProps } from "./features/shared";
import appIconUrl from "../../../../build/icons/icon-256.png";

const desktopFeatures: Record<string, LazyExoticComponent<ComponentType<FeatureProps>>> = {
  "image-editor": lazy(() => import("./features/image-editor/ImageEditorFeature")),
  "screenshot-stitch-redact": lazy(() => import("./features/screenshot-stitch-redact/ScreenshotStitchFeature")),
  "pdf-tools": lazy(() => import("./features/pdf-tools/PdfToolsFeature")),
  "gif-frame-editor": lazy(() => import("./features/gif-frame-editor/GifFrameEditorFeature")),
  "audio-toolkit": lazy(() => import("./features/audio-toolkit/AudioToolkitFeature")),
  "video-to-gif-webp": lazy(() => import("./features/video-to-gif-webp/VideoToGifWebpFeature")),
  "network-tools": lazy(() => import("./features/network-tools/NetworkToolsFeature")),
};

type WebResult = PlatformOutput & { data: Uint8Array };

const legacyTextToolIds = new Set([
  "base64", "url-encode", "html-escape", "json-escape", "unicode-escape", "hex-converter", "binary-converter",
  "json-formatter", "csv-json-converter", "yaml-json-converter", "json-schema-generator", "json-to-typescript", "jsonpath-tester",
  "text-case-converter", "text-sort-deduplicate", "regex-tester", "text-diff", "number-base-converter", "url-parser", "utm-url-builder",
  "password-generator", "lorem-ipsum-generator", "cron-generator", "color-converter", "html-entity-reference", "user-agent-parser", "robots-txt-generator", "sitemap-generator", "sql-formatter", "code-minifier",
  "jwt-decoder", "hash-generator", "hmac-generator", "uuid-generator", "xml-formatter", "code-beautifier", "http-status-codes", "mime-type-reference",
  "name-generator", "unit-converter", "easing-preview", "css-generator", "qr-code-generator", "barcode-generator", "seo-meta-generator",
  "base64-image-converter",
  "timestamp-converter", "date-time-tools", "markdown-tools", "markdown-html-converter", "csv-markdown-table-converter", "markdown-table-generator", "community-post-helper", "open-graph-preview",
  "retro-sfx-generator",
]);

function displayName(id: string): string { return id.replaceAll("-", " ").replace(/\b\w/g, (value) => value.toUpperCase()); }
function formatBytes(value?: number): string { if (value === undefined) return ""; if (value < 1024) return `${value} B`; if (value < 1024 * 1024) return `${(value / 1024).toFixed(1)} KB`; return `${(value / 1024 / 1024).toFixed(1)} MB`; }
function bytesToBlobPart(bytes: Uint8Array): ArrayBuffer { const copy = new ArrayBuffer(bytes.byteLength); new Uint8Array(copy).set(bytes); return copy; }

function makeBrowserImageCodec() {
  return { convert: async (data: Uint8Array, options: Record<string, unknown>) => {
    const bitmap = await createImageBitmap(new Blob([bytesToBlobPart(data)], { type: "image/*" }));
    const width = typeof options.width === "number" ? Math.max(1, Math.round(options.width)) : bitmap.width;
    const height = typeof options.height === "number" ? Math.max(1, Math.round(options.height)) : bitmap.height;
    const format = options.outputFormat === "png" || options.outputFormat === "jpeg" || options.outputFormat === "webp" ? options.outputFormat : "webp";
    const canvas = document.createElement("canvas"); canvas.width = width; canvas.height = height;
    const context = canvas.getContext("2d"); if (!context) throw new Error("Canvas is unavailable.");
    if (format === "jpeg") { context.fillStyle = typeof options.backgroundColor === "string" ? options.backgroundColor : "#fff"; context.fillRect(0, 0, width, height); }
    context.drawImage(bitmap, 0, 0, width, height); bitmap.close();
    const blob = await new Promise<Blob>((resolve, reject) => canvas.toBlob((candidate) => candidate ? resolve(candidate) : reject(new Error("Image export failed.")), `image/${format}`, format === "png" ? undefined : 0.85));
    return { data: new Uint8Array(await blob.arrayBuffer()), mimeType: blob.type, extension: format === "jpeg" ? "jpg" : format };
  } };
}

export function App() {
  const isElectron = Boolean(window.suwol);
  const [settings, setSettings] = useState<AppSettings>(defaultSettings);
  const [jobs, setJobs] = useState<Job[]>([]);
  const [query, setQuery] = useState("");
  const [selectedToolId, setSelectedToolId] = useState("file-hash-generator");
  const [input, setInput] = useState<InputSource | undefined>();
  const [output, setOutput] = useState<OutputTarget>({ ...defaultOutputTarget });
  const [options, setOptions] = useState<Record<string, unknown>>({ outputFormat: "webp", quality: 85, width: 800, height: 600, mode: "trim" });
  const [textDraft, setTextDraft] = useState("");
  const [webFiles, setWebFiles] = useState<Map<string, File>>(new Map());
  const [webResults, setWebResults] = useState<WebResult[]>([]);
  const [showJobs, setShowJobs] = useState(false);
  const [error, setError] = useState("");
  const [onboarding, setOnboarding] = useState(false);
  const [updateState, setUpdateState] = useState<UpdateState>({ status: "disabled", supported: false, platform: "unsupported", version: "" });
  const searchRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (!isElectron) return;
    void window.suwol!.app.getBootstrap().then((bootstrap) => { setSettings(bootstrap.settings); setJobs(bootstrap.jobs); setUpdateState(bootstrap.update); setOutput((current) => ({ ...current, collision: bootstrap.settings.collisionPolicy, directory: bootstrap.settings.defaultOutputDirectory })); setOptions(bootstrap.settings.toolOptions["file-hash-generator"] ?? getToolById("file-hash-generator")?.defaultOptions ?? {}); setOnboarding(!bootstrap.settings.onboardingComplete); });
    const removeJobs = window.suwol!.jobs.onUpdate((job) => setJobs((current) => [job, ...current.filter((candidate) => candidate.id !== job.id)]));
    const removeUpdates = window.suwol!.updates.onState(setUpdateState);
    return () => { removeJobs(); removeUpdates(); };
  }, [isElectron]);

  useEffect(() => {
    let link = document.querySelector<HTMLLinkElement>('link[rel="icon"]');
    if (!link) { link = document.createElement("link"); link.rel = "icon"; document.head.appendChild(link); }
    link.type = "image/png";
    link.href = appIconUrl;
  }, []);

  useEffect(() => { const handler = (event: KeyboardEvent) => { if (event.key === "/" && document.activeElement?.tagName !== "INPUT" && document.activeElement?.tagName !== "TEXTAREA") { event.preventDefault(); searchRef.current?.focus(); } if (event.key === "Escape") searchRef.current?.blur(); }; window.addEventListener("keydown", handler); return () => window.removeEventListener("keydown", handler); }, []);
  useEffect(() => { const handler = (event: ClipboardEvent) => { const currentTool = getToolById(selectedToolId); if (document.activeElement?.tagName === "INPUT" || document.activeElement?.tagName === "TEXTAREA") return; if (!currentTool?.capabilities.includes("clipboard")) return; if (isElectron && currentTool.inputFormats.includes("image") && event.clipboardData?.items.length) { event.preventDefault(); void window.suwol!.clipboard.createImageSource().then(rememberInput).catch(() => undefined); return; } if (!currentTool.inputFormats.includes("text")) return; const pasted = event.clipboardData?.getData("text/plain"); if (!pasted) return; if (legacyTextToolIds.has(currentTool.id)) setTextDraft(pasted); else { const file = new File([pasted], "clipboard.txt", { type: "text/plain" }); rememberInput(toWebSource([file])); } }; window.addEventListener("paste", handler); return () => window.removeEventListener("paste", handler); }, [isElectron, selectedToolId]);

  const selectedTool = getToolById(selectedToolId) ?? tools[0]!;
  const filteredTools = useMemo(() => { const needle = query.trim().toLowerCase(); if (needle === "__favorites__") return tools.filter((tool) => !tool.hidden && settings.favorites.includes(tool.id)); if (needle === "__recent__") return settings.recentTools.map((id) => getToolById(id)).filter((tool): tool is NonNullable<typeof tool> => tool !== undefined && !tool.hidden); return tools.filter((tool) => !tool.hidden && (!needle || [tool.name, tool.description, ...tool.keywords].join(" ").toLowerCase().includes(needle))); }, [query, settings.favorites, settings.recentTools]);
  const groupedTools = useMemo(() => categories.map((category) => ({ category, tools: filteredTools.filter((tool) => tool.category === category.id) })).filter((group) => group.tools.length > 0), [filteredTools]);
  const activeJobs = jobs.filter((job) => ["queued", "running", "paused", "failed"].includes(job.status));

  function rememberInput(source: InputSource | undefined): void { if (!source) return; setInput(source); const recentItems = [...source.items, ...settings.recentItems.filter((item) => !source.items.some((candidate) => candidate.handleId === item.handleId))].slice(0, 40); const recentFolders = source.kind === "folder" && source.label ? [source.label, ...settings.recentFolders.filter((folder) => folder !== source.label)].slice(0, 20) : settings.recentFolders; const next = { ...settings, recentItems, recentFolders }; setSettings(next); if (isElectron) void window.suwol!.settings.update({ recentItems, recentFolders }); }
  function selectTool(id: string): void { setSelectedToolId(id); setQuery(""); setInput(undefined); setTextDraft(""); setOptions(settings.toolOptions[id] ?? getToolById(id)?.defaultOptions ?? {}); setWebResults([]); setError(""); setShowJobs(false); const recentTools = [id, ...settings.recentTools.filter((candidate) => candidate !== id)].slice(0, 20); const frequentTools = { ...settings.frequentTools, [id]: (settings.frequentTools[id] ?? 0) + 1 }; setSettings((current) => ({ ...current, recentTools, frequentTools })); if (isElectron) void window.suwol!.settings.update({ recentTools, frequentTools }); }
  function toggleFavorite(id: string): void { const favorites = settings.favorites.includes(id) ? settings.favorites.filter((candidate) => candidate !== id) : [...settings.favorites, id]; const next = { ...settings, favorites }; setSettings(next); if (isElectron) void window.suwol!.settings.update({ favorites }); }
  function updateOptions(patch: Record<string, unknown>): void { const next = { ...options, ...patch }; setOptions(next); const toolOptions = { ...settings.toolOptions, [selectedTool.id]: next }; setSettings((current) => ({ ...current, toolOptions })); if (isElectron) void window.suwol!.settings.update({ toolOptions }); }
  function replaceOptions(next: Record<string, unknown>): void { setOptions(next); const toolOptions = { ...settings.toolOptions, [selectedTool.id]: next }; setSettings((current) => ({ ...current, toolOptions })); if (isElectron) void window.suwol!.settings.update({ toolOptions }); }

  async function chooseFiles(): Promise<void> {
    setError("");
    if (isElectron) { rememberInput(await window.suwol!.files.pick()); return; }
    const element = document.getElementById("web-file-input") as HTMLInputElement | null; element?.click();
  }
  async function chooseFolder(): Promise<void> {
    setError("");
    if (isElectron) { rememberInput(await window.suwol!.files.pickFolder(true)); return; }
    const element = document.getElementById("web-folder-input") as HTMLInputElement | null; element?.click();
  }
  function toWebSource(files: FileList | File[]): InputSource {
    const nextMap = new Map(webFiles); const items: InputItem[] = [];
    Array.from(files).forEach((file, index) => { const handleId = `web-${Date.now()}-${index}-${file.name}`; nextMap.set(handleId, file); items.push({ handleId, name: file.name, relativePath: (file as File & { webkitRelativePath?: string }).webkitRelativePath || file.name, size: file.size, mimeType: file.type }); });
    setWebFiles(nextMap); return { kind: "files", items, includeSubdirectories: items.some((item) => item.relativePath.includes("/")), origin: "dialog" };
  }
  function onWebFiles(event: ChangeEvent<HTMLInputElement>): void { if (event.target.files?.length) rememberInput(toWebSource(event.target.files)); event.target.value = ""; }
  async function onDrop(event: DragEvent<HTMLDivElement>): Promise<void> {
    event.preventDefault(); setError("");
    const paths = Array.from(event.dataTransfer.files);
    if (isElectron) { const candidates = paths.map((file) => (file as File & { path?: string }).path).filter((value): value is string => Boolean(value)); if (candidates.length) rememberInput(await window.suwol!.files.adoptDroppedPaths(candidates)); return; }
    if (paths.length) rememberInput(toWebSource(paths));
  }

  async function chooseOutputFolder(): Promise<void> { if (isElectron) { const directory = await window.suwol!.files.pickOutputFolder(); if (directory) { setOutput((current) => ({ ...current, kind: "directory", directory })); setSettings((current) => ({ ...current, defaultOutputDirectory: directory })); void window.suwol!.settings.update({ defaultOutputDirectory: directory }); } } }

  async function runSelectedTool(optionsOverride?: Record<string, unknown>): Promise<void> {
    let runInput = input;
    if (!runInput?.items.length && legacyTextToolIds.has(selectedTool.id)) {
      runInput = isElectron ? await window.suwol!.clipboard.createTextSource(textDraft) : toWebSource([new File([textDraft], "clipboard.txt", { type: "text/plain" })]);
    }
    if (!selectedTool.migrated || !runInput?.items.length) { setError("파일을 추가하거나 텍스트를 입력하세요."); return; }
    setError(""); setWebResults([]);
    try {
      const runOptions = optionsOverride ?? options;
      if (isElectron) { await window.suwol!.jobs.enqueue({ toolId: selectedTool.id, input: runInput, output, options: runOptions }); setShowJobs(true); return; }
      const { executeJob } = await import("@suwol/core");
      const resolved: ResolvedInput[] = runInput.items.map((item) => ({ ...item, read: async () => new Uint8Array(await webFiles.get(item.handleId)!.arrayBuffer()) }));
      const io: FileIoAdapter = { writeOutput: async ({ input: source, output: processed }) => { if (!processed.data) throw new Error("이 작업은 Electron 파일 출력이 필요합니다."); const record: WebResult = { inputName: source.name, outputName: processed.name, mimeType: processed.mimeType, size: processed.data.byteLength, data: processed.data }; setWebResults((current) => [...current, record]); return record; } };
      await executeJob({ job: { id: `web-${Date.now()}`, toolId: selectedTool.id, options: runOptions, output }, inputs: resolved }, io, { imageCodec: makeBrowserImageCodec() });
    } catch (caught) { setError(caught instanceof Error ? caught.message : "작업에 실패했습니다."); }
  }

  function downloadWebResult(result: WebResult): void { const url = URL.createObjectURL(new Blob([bytesToBlobPart(result.data)], { type: result.mimeType })); const anchor = document.createElement("a"); anchor.href = url; anchor.download = result.outputName; anchor.click(); URL.revokeObjectURL(url); }

  async function finishOnboarding(): Promise<void> { const next = { ...settings, onboardingComplete: true }; setSettings(next); setOnboarding(false); if (isElectron) await window.suwol!.settings.update({ onboardingComplete: true, collisionPolicy: settings.collisionPolicy, defaultOutputDirectory: settings.defaultOutputDirectory }); }

  return <div className="app-shell">
    <aside className={`sidebar${settings.sidebarCollapsed ? " sidebar--collapsed" : ""}`}>
      <div className="brand"><img className="brand-mark" src={appIconUrl} alt="Suwol Tools" />{!settings.sidebarCollapsed && <span><strong>Suwol</strong><small>Tools</small></span>}</div>
      {!settings.sidebarCollapsed && <>
        <div className="search-wrap"><input ref={searchRef} value={query} onChange={(event) => setQuery(event.target.value)} placeholder="도구 검색…  /" aria-label="도구 검색" /></div>
        <nav className="quick-nav"><button onClick={() => { setQuery(""); setShowJobs(false); }}>⌂ 홈</button><button onClick={() => setQuery("__favorites__")}>★ 즐겨찾기 <em>{settings.favorites.length}</em></button><button onClick={() => setQuery("__recent__")}>◷ 최근 사용 <em>{settings.recentTools.length}</em></button><button onClick={() => setShowJobs(true)}>▣ 작업 센터 <em>{activeJobs.length}</em></button></nav>
        <div className="category-list">{groupedTools.map(({ category, tools: groupTools }) => <section key={category.id}><h3>{category.name}</h3>{groupTools.map((tool) => <button key={tool.id} className={selectedTool.id === tool.id && !showJobs ? "tool-link tool-link--active" : "tool-link"} onClick={() => selectTool(tool.id)}><span className="tool-dot">{tool.icon === "image" ? "▧" : tool.icon === "shield" ? "◇" : "•"}</span>{tool.name}</button>)}</section>)}</div>
      </>}
      <button className="collapse-button" onClick={() => { const sidebarCollapsed = !settings.sidebarCollapsed; setSettings((current) => ({ ...current, sidebarCollapsed })); if (isElectron) void window.suwol!.settings.update({ sidebarCollapsed }); }}>{settings.sidebarCollapsed ? "→" : "←"}</button>
    </aside>
    <main className="main-content">
      <header className="topbar"><div><span className="eyebrow">{isElectron ? "DESKTOP WORKSPACE" : "WEB COMPATIBILITY"}</span><h1>{showJobs ? "작업 센터" : selectedTool.name}</h1></div><div className="top-actions"><button className="secondary-button" onClick={() => setShowJobs((current) => !current)}>◷ {activeJobs.length} 작업</button>{isElectron && <button className="secondary-button" onClick={() => void window.suwol!.cache.clear()}>임시 입력 비우기</button>}{isElectron && <UpdateControls state={updateState} onState={setUpdateState} />}<button className="primary-button" onClick={() => toggleFavorite(selectedTool.id)}>{settings.favorites.includes(selectedTool.id) ? "★" : "☆"}</button></div></header>
      {showJobs ? <JobCenter jobs={jobs} onCancel={(id) => void window.suwol?.jobs.cancel(id)} onCancelAll={() => void window.suwol?.jobs.cancelAll()} onPause={(id) => void window.suwol?.jobs.pause(id)} onResume={(id) => void window.suwol?.jobs.resume(id)} onRetry={(id) => void window.suwol?.jobs.retry(id)} onClear={() => void window.suwol?.jobs.clearCompleted()} onOpen={(id) => void window.suwol?.jobs.openOutput(id)} onOpenFile={(id) => void window.suwol?.jobs.openFile(id)} onCopy={(id) => void window.suwol?.jobs.copyResult(id)} /> : <>
        <section className="tool-intro"><span className="category-pill">{categories.find((category) => category.id === selectedTool.category)?.name}</span><p>{selectedTool.description}</p><div className="metadata-row"><span>입력: {selectedTool.inputFormats.join(", ")}</span><span>출력: {selectedTool.outputFormats.join(", ")}</span><span>{selectedTool.migrated ? "파일·폴더에서 바로 처리" : "웹 기능으로 계속 사용"}</span></div></section>
        {isElectron && desktopFeatures[selectedTool.id] ? <Suspense fallback={<section className="panel loading-feature">편집 도구를 불러오는 중…</section>}>{(() => { const Feature = desktopFeatures[selectedTool.id]!; return <Feature tool={selectedTool} input={input} options={options} output={output} error={error} isElectron={isElectron} onInput={setInput} onOptions={updateOptions} onReplaceOptions={replaceOptions} onOutput={(patch) => setOutput((current) => ({ ...current, ...patch }))} onChooseFiles={() => void chooseFiles()} onChooseFolder={() => void chooseFolder()} onChooseOutput={() => void chooseOutputFolder()} onDrop={(event) => void onDrop(event)} onRun={(next) => void runSelectedTool(next)} />; })()}</Suspense> : selectedTool.migrated ? <ToolWorkspace toolId={selectedTool.id} input={input} textDraft={textDraft} output={output} options={options} error={error} webResults={webResults} onTextDraft={setTextDraft} onChooseFiles={() => void chooseFiles()} onChooseFolder={() => void chooseFolder()} onChooseOutput={() => void chooseOutputFolder()} onDrop={(event) => void onDrop(event)} onRun={() => void runSelectedTool()} onOptions={updateOptions} onOutput={(patch) => setOutput((current) => ({ ...current, ...patch }))} onWebFiles={onWebFiles} onDownload={downloadWebResult} /> : <FallbackCard toolId={selectedTool.id} />}
      </>}
    </main>
    {onboarding && <Onboarding settings={settings} onChange={(patch) => setSettings((current) => ({ ...current, ...patch }))} onFinish={() => void finishOnboarding()} onChooseOutput={chooseOutputFolder} />}
  </div>;
}

